import React, { useEffect, useState } from "react";
import Sidebar from "../components/Sidebar";
import Navbar from "../components/Navbar";
import API from "../api";

function HistoryPage() {
  const user = JSON.parse(localStorage.getItem("user"));
  const [reports, setReports] = useState([]);

  useEffect(() => {
    fetchReports();
  }, []);

  const fetchReports = async () => {
    try {
      const res = await API.get(`/reports?patient_name=${encodeURIComponent(user?.name || "")}`);
      setReports(res.data || []);
    } catch (error) {
      alert("Failed to load history");
    }
  };

  const downloadPDF = async (reportId) => {
    try {
      const response = await API.get(`/generate-pdf/${reportId}`, {
        responseType: "blob"
      });

      const blob = new Blob([response.data], { type: "application/pdf" });
      const url = window.URL.createObjectURL(blob);
      const link = document.createElement("a");
      link.href = url;
      link.download = `doctor_report_${reportId}.pdf`;
      document.body.appendChild(link);
      link.click();
      link.remove();
      window.URL.revokeObjectURL(url);
    } catch (error) {
      alert("PDF download failed");
    }
  };

  return (
    <div className="dashboard-layout">
      <Sidebar role="patient" />

      <div className="main-content">
        <Navbar
          title="Prediction History"
          subtitle="View your previous AI doctor recommendations"
        />

        <div className="dashboard-card">
          {reports.length === 0 ? (
            <div className="text-center py-5">
              <h4>No history found</h4>
              <p className="text-muted">Your previous predictions will appear here.</p>
            </div>
          ) : (
            <div className="table-responsive">
              <table className="table align-middle">
                <thead>
                  <tr>
                    <th>#</th>
                    <th>Disease</th>
                    <th>Doctor</th>
                    <th>Specialization</th>
                    <th>Confidence</th>
                    <th>Date</th>
                    <th>PDF</th>
                  </tr>
                </thead>
                <tbody>
                  {reports.map((report, index) => (
                    <tr key={report.id}>
                      <td>{index + 1}</td>
                      <td className="text-capitalize">{report.predicted_disease}</td>
                      <td>{report.predicted_doctor}</td>
                      <td>{report.specialization}</td>
                      <td>{report.confidence}%</td>
                      <td>{report.created_at}</td>
                      <td>
                        <button
                          className="btn btn-sm btn-premium"
                          onClick={() => downloadPDF(report.id)}
                        >
                          Download
                        </button>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>
          )}
        </div>
      </div>
    </div>
  );
}

export default HistoryPage;
